list1=[]
list2=[]
list3=[]
atag = soup.find_all(name='a', class_='storylink')
for row in atag:
  atext = row.text
  alink = row['href']
  list1.append(atext)
  list2.append(alink)

au = soup.find_all(name='span',class_='score')
for row in au:
  # print(row.getText().split(sep=" ")[0])
  list3.append(int(row.getText().split(sep=" ")[0]))

